class Solution {
    public int maxStability(int n, int[][] edges, int k) {
        int[][] graph = new int[n][n];
        for (int[] edge : edges) {
            graph[edge[0]][edge[1]] = edge[2];
            graph[edge[1]][edge[0]] = edge[2];
        }
        boolean[] visited = new boolean[n];
        int maxStability = 0;
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                maxStability = Math.max(maxStability, dfs(graph, visited, i, k));
            }
        }
        return maxStability;
    }
    private int dfs(int[][] graph, boolean[] visited, int node, int k) {
        visited[node] = true;
        int minStrength = Integer.MAX_VALUE;
        for (int neighbor = 0; neighbor < graph.length; neighbor++) {
            if (graph[node][neighbor] != 0 && !visited[neighbor]) {
                minStrength = Math.min(minStrength, dfs(graph, visited, neighbor, k));
            }
        }
        return Math.min(minStrength, upgradeEdge(graph, node, k));
    }
    private int upgradeEdge(int[][] graph, int node, int k) {
        int minStrength = Integer.MAX_VALUE;
        for (int neighbor = 0; neighbor < graph.length; neighbor++) {
            if (graph[node][neighbor] != 0 && k > 0) {
                graph[node][neighbor] *= 2;
                graph[neighbor][node] *= 2;
                k--;
                minStrength = Math.min(minStrength, graph[node][neighbor]);
            }
        }
        return minStrength;
    }
}
